// countingWriter wraps an io.Writer and tracks total bytes written.
// Reads of the count are safe to call concurrently with Write.
type countingWriter struct {
	w io.Writer
	n atomic.Int64
}

func (cw *countingWriter) Write(p []byte) (int, error) {
	n, err := cw.w.Write(p)
	cw.n.Add(int64(n))
	return n, err
}

func (cw *countingWriter) Count() int64 { return cw.n.Load() }

// startPackEncodeProgress emits in-place "encoding pack..." updates to
// dest while materialized push is spooling its body. Returns a stop
// function that finalizes the line with a permanent "done" message;
// safe to call exactly once (typically via defer). When dest is nil
// (non-verbose mode) returns a no-op stop, so callers don't need to
// special-case verbosity.
//
// Bytes-written and elapsed time are both shown — bytes alone are
// misleading because go-git's encoder does its delta-selection work
// before writing any output, so the byte counter sits at zero through
// the slow phase. Elapsed time gives the user a heartbeat regardless.
func startPackEncodeProgress(cw *countingWriter, dest io.Writer) func() {
	if dest == nil {
		return func() {}
	}
	start := time.Now()
	ticker := time.NewTicker(500 * time.Millisecond)
	stop := make(chan struct{})
	done := make(chan struct{})
	go func() {
		defer close(done)
		for {
			select {
			case <-stop:
				return
			case <-ticker.C:
				fmt.Fprintf(dest, "encoding pack: %s, elapsed %s\r",
					humanizeBytes(cw.Count()), time.Since(start).Round(time.Second))
			}
		}
	}()
	return func() {
		ticker.Stop()
		close(stop)
		<-done
		fmt.Fprintf(dest, "encoding pack: %s in %s\n",
			humanizeBytes(cw.Count()), time.Since(start).Round(time.Second))
	}
}

// humanizeBytes renders n in IEC units with one decimal place for KB+
// (e.g. "47.3 MB"). Anything below 1 KB is shown as raw bytes.
func humanizeBytes(n int64) string {
	const (
		kb = 1024
		mb = kb * 1024
		gb = mb * 1024
	)
	switch {
	case n < kb:
		return fmt.Sprintf("%d B", n)
	case n < mb:
		return fmt.Sprintf("%.1f KB", float64(n)/float64(kb))
	case n < gb:
		return fmt.Sprintf("%.1f MB", float64(n)/float64(mb))
	default:
		return fmt.Sprintf("%.1f GB", float64(n)/float64(gb))
	}
}

